import{c as e,Q as a,j as n,m as s}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Agent Harness Engineering — The Rise of the AI Control Plane","description":"","frontmatter":{"url":"https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d","date":"2026-04-23T00:00:00.000Z","authors":"Adnan Masood","related":"research/agent-harness/references/2026-04-adnan-masood-agent-control-plane.md","source":"Medium (Adnan Masood, PhD)","tags":["control-plane","harness-architecture","PEV-loop","cost-optimization","MCP"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-04-23-adnan-masood-ai-control-plane.md","filePath":"research/ai-articles/scored/2026-04-23-adnan-masood-ai-control-plane.md","lastUpdated":1779901665000}'),o={name:"research/ai-articles/scored/2026-04-23-adnan-masood-ai-control-plane.md"};function r(d,t,i,l,c,p){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="agent-harness-engineering-—-the-rise-of-the-ai-control-plane" tabindex="-1">Agent Harness Engineering — The Rise of the AI Control Plane <a class="header-anchor" href="#agent-harness-engineering-—-the-rise-of-the-ai-control-plane" aria-label="Permalink to &quot;Agent Harness Engineering — The Rise of the AI Control Plane&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a><br><strong>作者</strong>：Adnan Masood, PhD<br><strong>歸檔日期</strong>：2026-05-10<br><strong>Note</strong>: 完整版在 <code>research/agent-harness/references/2026-04-adnan-masood-agent-control-plane.md</code></p><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>8/10</td><td>PEV loop + cost tactics 可直接套用</td></tr><tr><td>B. 創新性</td><td>6/10</td><td>已知模式的整合，「Control Plane」框架是新穎標籤</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>行業統計有引用，cost 數字有依據</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>哈ness 架構清楚，但有些建議偏通用</td></tr><tr><td>E. 泛化性</td><td>9/10</td><td>Enterprise-focused，廣泛適用</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.5/10</strong></td><td>8×0.3 + 6×0.2 + 7×0.2 + 7×0.15 + 9×0.15 = 7.50</td></tr></tbody></table><p><strong>整合決策</strong>：RULE — PEV loop 補充進 <code>harness-design.md</code>，cost tactics 補充進 <code>subagent-strategy.md</code><br><strong>整合位置</strong>：<code>.claude/refs/harness-design.md</code> §PGE 決策樹<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Harness 是 AI 系統的「operating system」：管理 context、工具執行、安全控制、session memory。文章稱 65% 的企業 AI 失敗源於 harness 缺陷（非推理）。Plan-Execute-Verify (PEV) loop + human-in-the-loop gates 是核心設計模式。Token 成本優化：prefix stability + KV-cache → $3.00→$0.30 per million tokens (10x reduction)。</p><hr><h2 id="核心主張" tabindex="-1">核心主張 <a class="header-anchor" href="#核心主張" aria-label="Permalink to &quot;核心主張&quot;">​</a></h2><h3 id="_1-harness-ai-control-plane" tabindex="-1">1. Harness = AI Control Plane <a class="header-anchor" href="#_1-harness-ai-control-plane" aria-label="Permalink to &quot;1. Harness = AI Control Plane&quot;">​</a></h3><p>5 層架構：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Layer 5: Observability (logs, traces, metrics)</span></span>
<span class="line"><span>Layer 4: Safety &amp; Security (guardrails, sandboxing)</span></span>
<span class="line"><span>Layer 3: Context Management (prefix stability, KV cache)</span></span>
<span class="line"><span>Layer 2: Tool Execution (function calling, MCP)</span></span>
<span class="line"><span>Layer 1: Agent Loop (planner, executor, evaluator)</span></span></code></pre></div><h3 id="_2-plan-execute-verify-pev-loop" tabindex="-1">2. Plan-Execute-Verify (PEV) Loop <a class="header-anchor" href="#_2-plan-execute-verify-pev-loop" aria-label="Permalink to &quot;2. Plan-Execute-Verify (PEV) Loop&quot;">​</a></h3><p>類似 Anthropic 的 PGE（Planner-Generator-Evaluator），但強調 human-in-the-loop gates：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan: 分解任務，識別高風險步驟</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Execute: 在沙箱環境執行</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>Verify: 確定性工具驗證（非 LLM 自評）</span></span>
<span class="line"><span>  ↓ [如果高風險] ↓</span></span>
<span class="line"><span>Human Gate: 人類審批後繼續</span></span></code></pre></div><h3 id="_3-65-失敗率的根因分析" tabindex="-1">3. 65% 失敗率的根因分析 <a class="header-anchor" href="#_3-65-失敗率的根因分析" aria-label="Permalink to &quot;3. 65% 失敗率的根因分析&quot;">​</a></h3><p>65% 企業 AI 失敗來自 harness 缺陷：</p><ul><li>35%：context 管理失效（token overflow、prefix 不穩定）</li><li>20%：工具執行錯誤（timeout、schema mismatch）</li><li>10%：安全控制不足（prompt injection、data leakage）</li></ul><h3 id="_4-token-成本優化策略" tabindex="-1">4. Token 成本優化策略 <a class="header-anchor" href="#_4-token-成本優化策略" aria-label="Permalink to &quot;4. Token 成本優化策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>策略</th><th>效果</th><th>實作</th></tr></thead><tbody><tr><td>Prefix stability</td><td>90%+ cache hit</td><td>靜態 CLAUDE.md 不 mid-session 改</td></tr><tr><td>KV-cache</td><td>10x cost reduction</td><td><code>settings.json</code> prompt caching</td></tr><tr><td>Deferred tool loading</td><td>-40% schema tokens</td><td>Claude Code ToolSearch 機制</td></tr><tr><td>Context compaction</td><td>-60% context tokens</td><td><code>/compact</code> 主動觸發</td></tr></tbody></table><hr><h2 id="對-cc-workspace-的映射" tabindex="-1">對 cc-workspace 的映射 <a class="header-anchor" href="#對-cc-workspace-的映射" aria-label="Permalink to &quot;對 cc-workspace 的映射&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文章概念</th><th>cc-workspace 對應</th><th>對齊狀態</th></tr></thead><tbody><tr><td>Control Plane 5 層</td><td><code>.claude/</code> 多層架構</td><td>✅</td></tr><tr><td>PEV Loop</td><td>PGE（plan-mode-expert + implementer + /deep-review）</td><td>⚠️ 無決策樹</td></tr><tr><td>Human-in-the-loop gates</td><td>生產紅線（二次確認）</td><td>✅</td></tr><tr><td>Prefix stability</td><td>output-discipline.md（不 mid-session 改規則）</td><td>✅</td></tr><tr><td>65% harness failure stat</td><td>支持 workspace 的 harness 投資優先級</td><td>✅ 驗證</td></tr></tbody></table><p><strong>Gap</strong>：PEV Loop 沒有正式的「高風險步驟識別」決策樹（何時觸發 Human Gate？）</p>`,26)])])}const m=e(o,[["render",r]]);export{g as __pageData,m as default};
